  const voiceChip=$('#cloudVoiceChip'); if(voiceChip) voiceChip.textContent = voiceReady ? 'Alexa e Google collegati' : (alexaReady ? 'Alexa collegata' : (googleReady ? 'Google collegato' : 'Assistenti da collegare'));
