function isBottleLike(result={}, state={}){
  const text=normalizeText([result.productName,result.brand,result.variant,result.productType,result.packageType,result.estimatedSize,...(result.visibleEvidence||[]),...(result.detectedText||[])].join(' '));
  return !!(result.isLiquid || state.category==='drinks' || /acqua|bottiglia|bevanda|naturale|frizzante|vera|levissima|sant.?anna|rocchetta|lete|uliveto/.test(text));
}
function getScanFormState(el, result={}){
  return {
    name: el.querySelector('[data-scan-name]')?.value?.trim()||'',
    brand: el.querySelector('[data-scan-brand]')?.value?.trim()||'',
    size: el.querySelector('[data-scan-size]')?.value?.trim() || result.estimatedSize || '',
    qty: Number(String(el.querySelector('[data-scan-qty]')?.value||'').replace(',','.'))||0,
    unit: el.querySelector('[data-scan-unit]')?.value?.trim()||'',
    expiry: el.querySelector('[data-scan-expiry]')?.value?.trim()||'',
    category: el.querySelector('[data-scan-cat]')?.value?.trim()||'',
    damage: el.querySelector('[data-scan-damage]')?.value?.trim()||'',
    result
  };
}
function getScanCompletionStatus(el, result={}){
  const s=getScanFormState(el,result);
  const brandRequired = !!result.brand && !s.brand && !el.dataset.voiceBrandDone;
  const sizeImportant = isBottleLike(result,s);
  const rawSize=String(s.size||'').toLowerCase();
  const sizeOk = (!!s.size && !/da confermare|capienza da confermare|1,5 l \/ 2 l/.test(rawSize)) || el.dataset.voiceSizeDone==='1';
  const guided = !!(result.liveProductCapture || result.guidedPhotoCapture || el.dataset.liveLabelTarget==='1' || result.requiresThreeScanFlow);
  const labelOk = !guided || !!result.labelScanMerged || el.dataset.liveFollowupStep==='expiry' || el.dataset.liveFollowupStep==='barcode' || el.dataset.liveFollowupStep==='done';
  const expiryRequired = guided && labelOk && el.dataset.voiceExpiryDone!=='1';
  const barcodeOk = !guided || !!(result.barcode || result.ean || result.code || result.productCode) || el.dataset.barcodeScanDone==='1' || el.dataset.liveFollowupStep==='done';
  const barcodeRequired = guided && labelOk && (!!s.expiry || el.dataset.voiceExpiryDone==='1') && !barcodeOk;
  const checks=[
    {key:'name', label:'Nome', ok:!!s.name && !/^es\./i.test(s.name) && !isBadScanName(s.name), required:true, warn:Number(result.confidence||0)<0.50},
    {key:'brand', label:'Marca', ok:!!s.brand || !!result.brand || !brandRequired || el.dataset.voiceBrandDone==='1', required:brandRequired, warn:!s.brand},
    {key:'size', label:'Formato', ok:!sizeImportant || sizeOk, required:sizeImportant && !sizeOk, warn:sizeImportant && !sizeOk, important:sizeImportant},
    {key:'qty', label:'Quantità', ok:s.qty>0 && !!s.unit, required:true},
    {key:'label', label:'Etichetta', ok:labelOk, required:guided && !labelOk, warn:guided && !labelOk, important:guided},
    {key:'expiry', label:'Scadenza', ok:!!s.expiry || el.dataset.voiceExpiryDone==='1', required:expiryRequired && !s.expiry, warn:!s.expiry && !expiryRequired},
    {key:'barcode', label:'Barcode', ok:barcodeOk, required:barcodeRequired, warn:guided && !barcodeOk},
    {key:'category', label:'Categoria', ok:!!s.category, required:true},
    {key:'damage', label:'Stato', ok:!!s.damage, required:true}
  ];
  const done=checks.filter(c=>c.ok).length;
  const missing=checks.filter(c=>c.required && !c.ok).map(c=>c.key);
  return {state:s, checks, done, total:checks.length, missing, warn:checks.filter(c=>c.warn && !c.ok).map(c=>c.key)};
}
function scanSummaryText(el, result={}){
  const info=getScanCompletionStatus(el,result), s=info.state;
  const parts=[];
  parts.push(`Prodotto: ${s.name || result.productName || 'non definito'}.`);
  if(s.brand || result.brand) parts.push(`Marca: ${s.brand || result.brand}.`);
  if(s.size) parts.push(`Formato/capienza: ${s.size}.`);
  if(s.qty>0) parts.push(`Quantità: ${String(s.qty).replace('.',',')} ${s.unit||'pz'}.`);
  if(s.expiry) parts.push(`Scadenza: ${s.expiry}.`); else parts.push('Scadenza ancora da confermare.');
  if(s.category) parts.push(`Categoria: ${catName(s.category)}.`);
  if(s.damage) parts.push(`Stato: ${s.damage}.`);
  if(info.missing.length){ parts.push(`Mi manca ancora: ${info.missing.map(k=>({name:'nome',brand:'marca',size:'formato/capienza',qty:'quantità',label:'etichetta',expiry:'scadenza',barcode:'barcode',category:'categoria',damage:'stato'}[k]||k)).join(', ')}.`); }
  else if(info.warn.includes('expiry') || info.warn.includes('brand')) parts.push('La scheda è utilizzabile; marca o scadenza sono opzionali se non visibili.');
  else parts.push('La scheda è completa e pronta per la conferma.');
  return parts.join(' ');
}
function renderScanCompletionStatus(el, result={}){
  const box=el?.querySelector('[data-scan-summary]');
  if(!box) return;
  const info=getScanCompletionStatus(el,result);
  const pct=Math.round((info.done/info.total)*100);
  const progress=info.checks.map(c=>`<div class="step ${c.ok?'ok':(c.warn?'warn':'')} ${c.important?'important':''}">${c.ok?'✓':'•'} ${esc(c.label)}</div>`).join('');
  const line = info.missing.length ? `Completamento ${pct}%. Mancano: ${info.missing.map(k=>({name:'nome',brand:'marca',size:'formato/capienza',qty:'quantità',label:'etichetta',expiry:'scadenza',barcode:'barcode',category:'categoria',damage:'stato'}[k]||k)).join(', ')}.` : (info.warn.length ? `Scheda utilizzabile. Opzionali non letti: ${info.warn.map(k=>({brand:'marca',size:'formato/capienza',label:'etichetta',expiry:'scadenza',barcode:'barcode'}[k]||k)).join(', ')}.` : 'Scheda completa: puoi confermare.');
  box.innerHTML=`<strong>Riepilogo smart</strong><div class="line">${esc(line)}</div><div class="scan-progress">${progress}</div>`;
}


function markScanFieldUserEdited(el, field, ev){
  if(!el || !field || !ev?.isTrusted) return;
  if(field.matches('[data-scan-name]')) el.dataset.userNameEdited='1';
  if(field.matches('[data-scan-brand]')) el.dataset.userBrandEdited='1';
  if(field.matches('[data-scan-size]')) el.dataset.userSizeEdited='1';
  if(field.matches('[data-scan-expiry]')) el.dataset.userExpiryEdited='1';
  if(field.matches('[data-scan-cat]')) el.dataset.userCategoryEdited='1';
  if(field.matches('[data-scan-unit]')) el.dataset.userUnitEdited='1';
  if(field.matches('[data-scan-qty]')) el.dataset.userQtyEdited='1';
  if(field.matches('[data-scan-damage]')) el.dataset.userDamageEdited='1';
}
function syncScanResultFromFields(el, result={}){
  if(!el || !result) return result;
  const read=(sel)=>String(el.querySelector(sel)?.value||'').trim();
  const name=read('[data-scan-name]');
  const brand=read('[data-scan-brand]');
  const size=read('[data-scan-size]');
  const qty=read('[data-scan-qty]');
  const unit=read('[data-scan-unit]');
  const expiry=read('[data-scan-expiry]');
  const cat=read('[data-scan-cat]');
  const damage=read('[data-scan-damage]');
  const trustedFromEvidence = result.labelScanMerged ? deriveTrustedLabelFields(result) : {};
  if(name && !/^es\./i.test(name) && !isBadScanName(name)) result.productName=name;
  else if(name && isBadScanName(name) && el.dataset.userNameEdited!=='1'){
    const field=el.querySelector('[data-scan-name]'); if(field) field.value='';
    if(isBadScanName(result.productName||'')) result.productName='';
  }
  if(brand && !isBadScanName(brand)) result.brand=brand;
  if(size) result.estimatedSize=size;
  if(hasStrongCurrentLabelEvidence(result)){
    if(el.dataset.userNameEdited!=='1' && trustedFromEvidence.productName && trustedFieldConflict(name, trustedFromEvidence.productName)) result.productName=trustedFromEvidence.productName;
    if(el.dataset.userBrandEdited!=='1' && trustedFromEvidence.brand && trustedFieldConflict(brand, trustedFromEvidence.brand)) result.brand=trustedFromEvidence.brand;
    if(el.dataset.userSizeEdited!=='1' && trustedFromEvidence.estimatedSize && (!size || /da confermare|capienza da confermare|1,5 l \/ 2 l|^0?5\s*l$/i.test(size))) result.estimatedSize=trustedFromEvidence.estimatedSize;
    if(el.dataset.userCategoryEdited!=='1' && trustedFromEvidence.category && (!cat || trustedFieldConflict(cat, trustedFromEvidence.category))) result.category=trustedFromEvidence.category;
  }
  if(qty && Number(qty)>0) result.quantity=Number(qty);
  if(unit) result.unit=unit;
  if(expiry) result.expiryDate=expiry;
  if(cat) result.category=cat;
  result=applyRealityCategoryGuard(result);
  if(damage) { result.damageType=damage; result.isDamaged=!/^integro$/i.test(damage); }
  const currentTokens=specificProductTokens([result.productName,result.brand,result.variant].join(' '));
  const matchTokens=specificProductTokens([result.bestMatchName,result.bestMatchSource,result.bestMatchProductType].join(' '));
  if(result.bestMatchName && currentTokens.length && matchTokens.length && tokenOverlapCount(currentTokens,matchTokens)===0){
    clearRejectedMemoryPrediction(result,'Memoria/AI locale ignorata: la scheda corrente è stata letta o corretta come prodotto diverso.');
  }
  el._scanResult=result;
  return result;
}
function refreshScanResultCard(el, result={}){
  result=syncScanResultFromFields(el,result||{});
  result=repairStaleScanFieldsFromLabelEvidence(el,result||{});
  renderScanCompletionStatus(el, result);
  if(!el?.classList.contains('confirmed')){
    const info=getScanCompletionStatus(el,result);
    if(info.missing.length===0) setScanVoiceHelper(el,'Tutto compilato: controlla il riepilogo finale e di conferma per aggiungere il prodotto in casa.','live');
  }
}
function parseNameFromSpeech(raw=''){
  let s=String(raw||'').trim();
  if(isBadScanName(s)) return '';
  const correction=s.match(/(?:non\s+(?:e|è)\s+.+?\s+(?:e|è)|ma\s+(?:e|è)|invece\s+(?:e|è)|correggi\s+(?:in|con)|metti\s+nome|cambia\s+in)\s+(.+)$/i);
  if(correction) s=correction[1].trim();
  s=s.replace(/^(no[, ]*)?(non e|non è|e|è|si chiama|nome|prodotto|correggi il nome in|correggi nome in|metti nome|metti)\s+/i,'').replace(/^(di marca)\s+/i,'').trim();
  s=s.replace(/\b(con|marca|brand|quantita|quantità|scadenza|categoria)\b.*$/i,'').trim();
  if(isBadScanName(s)) return '';
  return s;
}
function parseBrandFromSpeech(raw=''){
  const s=String(raw||'').trim();
  const direct=s.match(/(?:marca|brand|di marca|la marca e|la marca è)\s+(.+)/i);
  if(direct) return direct[1].replace(/\b(scadenza|quantita|quantità|categoria)\b.*$/i,'').trim();
  const corr=s.match(/(?:non\s+(?:e|è)\s+.+?\s+(?:e|è)|ma\s+(?:e|è)|invece\s+(?:e|è))\s+(.+)$/i);
  if(corr) return corr[1].trim();
  return '';
}
function speakCurrentScanSummary(el,result={}){
  const text=scanSummaryText(el,result);
  setScanVoiceHelper(el, text, 'live');
  if(liveScanSpeechEnabled) speakNatural(text,{flush:true, rate:1.0, pitch:1.02});
}
function getNextScanMicStep(el, result={}){
  const state=getScanFormState(el,result);
  if(!state.name || /^nome prodotto$/i.test(state.name) || /^es\./i.test(state.name) || (!el.dataset.voiceNameDone && Number(result.confidence||0)<0.45)) return 'name';
  if((!state.brand && !el.dataset.voiceBrandDone && Number(result.confidence||0)<0.92) || (result.labelScanMerged && !state.brand && !el.dataset.voiceBrandDone)) return 'brand';
  if(isBottleLike(result,state) && !state.size && !el.dataset.voiceSizeDone) return 'size';
  if(!(state.qty>0)) return 'qty';
  if(result.isDamaged && !el.dataset.voiceDamageDone) return 'damage';
  if(!state.category) return 'category';
  if(!state.expiry && !el.dataset.voiceExpiryDone && Number(result.confidence||0)>=0.72) return 'expiry';
  return 'confirm';
}
function scanMicPromptForStep(step, el, result={}){
  const damageType=(result.damageType||el.querySelector('[data-scan-damage]')?.value||'irregolarità');
  if(step==='name') return Number(result.confidence||0)<0.45 ? 'Il nome non mi convince del tutto. Dimmi come si chiama il prodotto.' : 'Dimmi il nome del prodotto.';
  if(step==='brand') return 'Dimmi anche la marca, se vuoi correggerla o completarla.';
  if(step==='size') return 'Dimmi la capienza o il formato. Per esempio: due litri, un litro e mezzo, cinquecento ml.';
  if(step==='qty') return 'Dimmi la quantità di pezzi. Puoi dire per esempio una bottiglia, due bottiglie o tre pezzi.';
  if(step==='expiry') return 'Se riesci, dimmi la data di scadenza. Puoi anche dire salta se non la vuoi inserire adesso.';
  if(step==='damage') return `Attenzione, vedo una possibile irregolarità: ${damageType}. Dimmi se è integro, ammaccato, rotto, aperto, congelato o con perdita.`;
  if(step==='category') return 'In che categoria lo metto? Per esempio alimentari, bevande, frutta, verdura, animali, casa, farmacia o acquario.';
  return 'La scheda è pronta. Se marca o scadenza non sono visibili puoi confermare lo stesso, oppure dimmi cosa correggere.';
}
function promptScannerConversation(el, result={}, force=false){
  if(!el) return;
  setActiveScannerResult(el);
  refreshScanResultCard(el,result);
  const step=getNextScanMicStep(el, result);
  scannerMicStep=step;
  const prompt=scanMicPromptForStep(step, el, result);
  setScanVoiceHelper(el, prompt, step==='damage' ? 'warn' : 'live');
  if(force || scannerMicLastPrompt!==prompt){ scannerMicLastPrompt=prompt; if(liveScanSpeechEnabled) speakNatural(prompt,{flush:true, rate:1.0, pitch:1.02}); }
}
function startScannerMic(autoSpeak=true){
  if(!scannerMicEnabled) { setMicToggleUi(); return; }
  if(scannerMicPausedBySpeech){ setMicToggleUi(); return; }
  const SR=window.SpeechRecognition || window.webkitSpeechRecognition;
  if(!SR){ toast('Microfono live non supportato da questo browser'); scannerMicEnabled=false; setMicToggleUi(); return; }
  if(scannerMicListening) return;
  scannerMicShouldRestart=true;
  const r=new SR();
  scannerMicRecognition=r; r.lang='it-IT'; r.interimResults=false; r.continuous=true;
  r.onstart=()=>{ scannerMicListening=true; setMicToggleUi(); };
  r.onresult=(e)=>{
    if(scannerMicPausedBySpeech || Date.now()<scannerMicEchoBlockUntil) return;
    for(let i=e.resultIndex;i<e.results.length;i++){
      const txt=e.results[i][0].transcript;
      handleScannerMicText(txt);
    }
  };
  r.onerror=(e)=>{
    if(e?.error==='not-allowed' || e?.error==='service-not-allowed'){ scannerMicEnabled=false; scannerMicShouldRestart=false; toast('Permesso microfono negato'); }
    else if(e?.error!=='aborted'){ toast('Microfono live: ripeti più lentamente'); }
    setMicToggleUi();
  };
  r.onend=()=>{ scannerMicListening=false; setMicToggleUi(); if(scannerMicShouldRestart && !scannerMicPausedBySpeech && (liveScanActive || $('#groceryScannerDialog')?.open)) setTimeout(()=>startScannerMic(false), 600); };
  try{ r.start(); if(autoSpeak) speakNatural('Microfono attivo. Possiamo parlare mentre inquadri il prodotto e fino alla compilazione completa della scheda.', {flush:false, rate:1.0, pitch:1.02}); }catch{}
}
function stopScannerMic(silent=false){
  scannerMicShouldRestart=false;
  try{ scannerMicRecognition?.stop(); }catch{}
  scannerMicRecognition=null; scannerMicListening=false; setMicToggleUi();
  if(!silent) toast('Microfono live disattivato');
}
function setScanFieldFromVoice(el, selector, value){
  const field=el?.querySelector(selector); if(!field) return false; field.value=value; field.dispatchEvent(new Event('input',{bubbles:true})); field.dispatchEvent(new Event('change',{bubbles:true})); return true;
}
function handleScannerMicText(text=''){
  const raw=String(text||'').trim(); if(!raw) return;
  learnVoiceLocally(raw,'scanner-heard');
  const norm=normalizeText(raw);
  const nowMic=Date.now();
  if(nowMic < scannerMicEchoBlockUntil && /(scatt|scatto|premi|inquadra|etichetta|scadenza|prodotto|analizz)/.test(norm)) return;
  if(/(ferma|disattiva).*(microfono|mic|voce)/.test(norm)){ scannerMicEnabled=false; stopScannerMic(); return; }
  if(/(attiva|riattiva).*(microfono|mic|voce)/.test(norm)){ scannerMicEnabled=true; setMicToggleUi(); startScannerMic(true); return; }
  if(/^(ripeti|aiuto|cosa devo fare)/.test(norm)){ const el=getActiveScannerResult(); if(el) promptScannerConversation(el, el._scanResult||{}, true); else if(liveScanAwaitNextOk && liveScanSpeechEnabled) speakNatural('Per continuare con il prossimo prodotto, dimmi okay oppure premi il pulsante dedicato.', {flush:true}); else if(liveScanSpeechEnabled) speakNatural('Mostrami un prodotto nel riquadro o scatta una foto, poi ti guiderò.', {flush:true}); return; }
  if(liveScanAwaitNextOk && /(ok|okay|va bene|continua|procedi|prossimo|vai avanti)/.test(norm)){ allowNextObjectScan(true); return; }
  if(liveScanActive && /(scatta|scatto|scatta ora|acquisisci|analizza adesso)/.test(norm)){
    const labelTarget=getLiveLabelTarget();
    if(liveScanBusy || Date.now()<liveScanCaptureLockUntil) return;
    if((liveScanPendingResult || hasPendingUnconfirmedScan()) && !labelTarget){
      const active=getActiveScannerResult();
      if(active) promptScannerConversation(active, active._scanResult||{}, true);
      return;
    }
    captureLiveFrame(true);
    return;
  }
  const el=getActiveScannerResult();
  if(!el){ if(liveScanAwaitNextOk && liveScanSpeechEnabled){ speakNatural('Sto aspettando il tuo okay per passare al prossimo oggetto.', {flush:true}); return; } if(liveScanSpeechEnabled) speakNatural('Ti ascolto. Inquadra un prodotto o scatta una foto per iniziare la compilazione.', {flush:true}); return; }
  setActiveScannerResult(el);
  const result=el._scanResult||{};
  if(/(rifai|nuova foto|ripeti foto)/.test(norm)){ el.querySelector('[data-retake]')?.click(); return; }
  if(/(riepilogo|riassunto|cosa hai capito|leggimi la scheda)/.test(norm)){ speakCurrentScanSummary(el,result); return; }
  if(/(conferma|aggiungi|va bene|ok conferma|tutto ok|conferma tutto)/.test(norm) && getNextScanMicStep(el,result)==='confirm'){ confirmScanResult(el,result); return; }
  if(applyScannerMicAnswer(el, result, raw)){ setTimeout(()=>{ const next=getActiveScannerResult()||el; if(next && !next.classList.contains('confirmed')) promptScannerConversation(next, next._scanResult||result, true); }, 280); return; }
  promptScannerConversation(el, result, true);
}
function applyScannerMicAnswer(el, result={}, raw=''){
  const norm=normalizeText(raw);
  const current=getNextScanMicStep(el,result);
  const spokenExpiryCandidate=parseExpiryFromSpeech(raw) || parseExpiryLoose(raw);
  const explicitName = current==='name' || /(^|\b)(non e|non è|si chiama|nome|prodotto|correggi.*nome|metti nome|cambia in|metti|^e |^è )(\b|$)/.test(norm);
  const explicitBrand = current==='brand' || /(^|\b)(marca|brand|di marca)(\b)/.test(norm);
  const explicitSize = current==='size' || /capienz|formato|litri|litro|ml|millilitri|mezzo litro|bottiglia grande|bottiglia piccola/.test(norm);
  const explicitQty = current==='qty' || /quantit|pezz|bottigli|unit/.test(norm);
  const explicitExpiry = current==='expiry' || /scad|exp|tmc|entro/.test(norm) || !!spokenExpiryCandidate;
  const explicitDamage = current==='damage' || /integr|rott|ammacc|apert|bucat|perdit|schiacci|rovinat|scadut|congelat|ghiacciat/.test(norm);
  const explicitCategory = current==='category' || /categori|bevand|aliment|frutt|verdur|animal|casa|farmac|acquar/.test(norm);

  if(explicitExpiry){
    if(/salta|non so|non la so|nessuna/.test(norm)){ el.dataset.voiceExpiryDone='1'; setScanVoiceHelper(el, 'Scadenza saltata per ora.', 'live'); refreshScanResultCard(el,result); return true; }
    const expiry=spokenExpiryCandidate;
    if(expiry){ setScanFieldFromVoice(el,'[data-scan-expiry]', expiry); rememberVoiceCorrection(raw,'expiry',expiry,result.expiryDate||''); el.dataset.voiceExpiryDone='1'; result.expiryDate=expiry; setScanVoiceHelper(el, `Scadenza aggiornata: ${expiry}.`, 'live'); refreshScanResultCard(el,result); return true; }
  }

  if(explicitName){
    if(/^(salta|skip|dopo|continua dopo|non so|non lo so|nessuno|nessuna|boh)(\s+ora|\s+per ora)?$/.test(norm)){
      el.dataset.voiceNameDone='1';
      const field=el.querySelector('[data-scan-name]'); if(field && !el.dataset.userNameEdited) field.value='';
      if(isBadScanName(result.productName||'')) result.productName='';
      setScanVoiceHelper(el,'Nome lasciato da compilare: non salvo comandi vocali come nome prodotto.', 'warn');
      refreshScanResultCard(el,result);
      return true;
    }
    const cleaned=parseNameFromSpeech(raw);
    if(cleaned && !isBadScanName(cleaned)){
      setScanFieldFromVoice(el,'[data-scan-name]', cleaned);
      rememberVoiceCorrection(raw,'name',cleaned,result.productName||'');
      el.dataset.voiceNameDone='1';
      result.productName=cleaned;
      setScanVoiceHelper(el, `Nome aggiornato: ${cleaned}.`, 'live');
      refreshScanResultCard(el,result);
      return true;
    } else if(explicitName){ setScanVoiceHelper(el,'Quel nome non è valido. Dimmi il nome reale del prodotto, per esempio Acqua Vera Naturale.', 'warn'); return true; }
  }

  if(explicitBrand){
    if(/salta|non so|nessuna|non c.e|non c'è/.test(norm)){ el.dataset.voiceBrandDone='1'; setScanVoiceHelper(el, 'Marca saltata per ora.', 'live'); refreshScanResultCard(el,result); return true; }
    const brand=parseBrandFromSpeech(raw) || parseNameFromSpeech(raw);
    if(brand && brand.length>1){
      setScanFieldFromVoice(el,'[data-scan-brand]', brand);
      rememberVoiceCorrection(raw,'brand',brand,result.brand||'');
      el.dataset.voiceBrandDone='1';
      result.brand=brand;
      setScanVoiceHelper(el, `Marca aggiornata: ${brand}.`, 'live');
      refreshScanResultCard(el,result);
      return true;
    }
  }

  const spokenSize=parseSizeFromSpeech(raw);
  if(explicitSize && spokenSize){
    setScanFieldFromVoice(el,'[data-scan-size]', spokenSize);
    rememberVoiceCorrection(raw,'size',spokenSize,result.estimatedSize||'');
    el.dataset.voiceSizeDone='1';
    result.estimatedSize=spokenSize;
    result.sizeConfirmed=true;
    setScanVoiceHelper(el, `Formato aggiornato: ${spokenSize}.`, 'live');
    refreshScanResultCard(el,result);
    return true;
  }

  const qtyInfo=parseQuantityUnitFromSpeech(raw);
  if(explicitQty && qtyInfo.quantity!=null){
    setScanFieldFromVoice(el,'[data-scan-qty]', String(qtyInfo.quantity).replace('.',','));
    rememberVoiceCorrection(raw,'quantity',String(qtyInfo.quantity),el.querySelector('[data-scan-qty]')?.value||'');
    if(qtyInfo.unit) setScanFieldFromVoice(el,'[data-scan-unit]', qtyInfo.unit);
    setScanVoiceHelper(el, `Quantità aggiornata: ${qtyInfo.quantity}${qtyInfo.unit ? ' ' + qtyInfo.unit : ''}.`, 'live');
    refreshScanResultCard(el,result);
    return true;
  }

  const expiry=spokenExpiryCandidate;
  if(explicitExpiry){
    if(/salta|non so|non la so|nessuna/.test(norm)){ el.dataset.voiceExpiryDone='1'; setScanVoiceHelper(el, 'Scadenza saltata per ora.', 'live'); refreshScanResultCard(el,result); return true; }
    if(expiry){ setScanFieldFromVoice(el,'[data-scan-expiry]', expiry); rememberVoiceCorrection(raw,'expiry',expiry,result.expiryDate||''); el.dataset.voiceExpiryDone='1'; result.expiryDate=expiry; setScanVoiceHelper(el, `Scadenza aggiornata: ${expiry}.`, 'live'); refreshScanResultCard(el,result); return true; }
  }

  const damage=detectDamageState(raw);
  if(explicitDamage && damage){
    setScanFieldFromVoice(el,'[data-scan-damage]', damage);
    rememberVoiceCorrection(raw,'damage',damage,result.damageType||'');
    el.dataset.voiceDamageDone='1';
    result.isDamaged = damage!=='Integro';
    result.damageType = damage==='Integro' ? '' : damage;
    setScanVoiceHelper(el, `Stato prodotto aggiornato: ${damage}.`, damage==='Integro' ? 'live' : 'warn');
    refreshScanResultCard(el,result);
    return true;
  }

  const cat=detectCategoryFromSpeech(raw);
  if(explicitCategory && cat){
    setScanFieldFromVoice(el,'[data-scan-cat]', cat);
    rememberVoiceCorrection(raw,'category',cat,result.category||'');
    setScanVoiceHelper(el, `Categoria aggiornata: ${catName(cat)}.`, 'live');
    refreshScanResultCard(el,result);
    return true;
  }

  if(current==='confirm' && /(conferma|aggiungi|ok|va bene|perfetto)/.test(norm)){ confirmScanResult(el,result); return true; }
  return false;
}
function buildResultVoiceSummary(result, summary){
  if(summary?.count>1){
    return `Ho visto ${summary.count} prodotti. ${summary.autoCount?summary.autoCount+' aggiunti in automatico. ':''}${summary.manualCount?'Controlla gli altri risultati e conferma quelli corretti.':'È tutto confermato.'}`;
  }
  const name=result.productName||'il prodotto';
  const parts=[`Ho riconosciuto ${name}.`];
  if(result.brand) parts.push(`Marca ${result.brand}.`);
  if(result.expiryDate) parts.push(`Scadenza letta: ${result.expiryDate}.`);
  else parts.push(pickPhrase(['Se vuoi, girami la confezione dal lato della scadenza per leggerla meglio.','Non vedo ancora la scadenza: prova a ruotare il prodotto e mostrarmi il punto dove è stampata.'], name));
  if(result.isDamaged) parts.push(`Attenzione: il prodotto sembra ${result.damageType||'danneggiato'}.`);
  if(result.needsManual) parts.push('Voglio una tua conferma finale su nome, quantità o dettagli letti.');
  else parts.push('Controlla il riepilogo e conferma se è corretto.');
  return parts.join(' ');
}

async function handleAiText(text, speak=false){
  openAiPanel();
  const cleaned=text.replace(/hey\s+spesa\s+pronta[:,]?/i,'').trim() || text;
  addAiMessage('user', cleaned);
  const answer=await aiAnswer(cleaned);
  addAiMessage('assistant', answer);
  if(speak) speakNatural(answer,{flush:true, rate:1.0, pitch:1.02});
}
function normalizeText(s){ return String(s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,''); }
function findItemBySpeech(query){
  const q=normalizeText(query);
  let best=null, bestLen=0;
  for(const item of state){
    const names=[item.id,...Object.values(item.names||{})].map(normalizeText);
    for(const n of names){
      if(n && (q.includes(n) || n.includes(q)) && n.length>bestLen){ best=item; bestLen=n.length; }
    }
  }
  return best;
}
function extractNumber(text){ const m=normalizeText(text).match(/(\d+(?:[\.,]\d+)?)/); return m ? Number(m[1].replace(',','.')) : null; }
function listBuyText(){
  const list=buyItems();
  if(!list.length) return 'Non manca niente: la lista della spesa è vuota.';
  return 'Devi comprare: '+list.map(i=>`${nameOf(i)} (${i.qty} ${i.unit})`).join(', ')+'.';
}
function aiExplainItem(item){
  const intel=consumptionIntel(item);
  return `${nameOf(item)}: hai ${item.qty} ${item.unit}. ${intel.reason} Velocità stimata: ${intel.velocity.toFixed(2)} ${item.unit}/giorno. ${statusOf(item)==='buy' ? 'Lo metto tra le priorità della spesa.' : 'Per ora non è urgente.'}`;
}
async function aiAnswer(text){
  const raw=text.trim();
  const q=normalizeText(raw);
  let m;
  if(q.includes('buongiorno') || q.includes('ciao') || q.includes('buonasera')) return aiGreetingText();
  if(q.includes('cosa ricordi') || q.includes('che ricordi') || q.includes('memoria')) return memorySummaryText();
  if(q.includes('dimentica tutto') || q.includes('cancella memoria')){ aiMemory=defaultAiMemory(); saveAiMemory(); return 'Ok, ho cancellato la memoria locale dell’assistente.'; }
  if(q.includes('fotografa') || q.includes('foto spesa') || q.includes('scanner') || q.includes('modalita frigo')){ openGroceryScanner(false); return 'Perfetto, ho aperto la modalità foto spesa. Fotografa un articolo alla volta: se non vedo bene ti chiedo di rifarla.'; }
  if(q.includes('cosa devo comprare') || q.includes('lista della spesa') || q.includes('che manca') || q.includes('cosa manca')) return listBuyText();
  if(q.includes('ho fatto la spesa') || q.includes('spesa fatta')){ openGroceryScanner(true); return 'Perfetto. Prima di chiudere la spesa completa il controllo con foto: scatta un articolo alla volta e conferma tutto solo alla fine.'; }
  m=q.match(/siamo\s+(\d+)\s+persone|(?:metti|imposta|aggiorna).*?(\d+)\s+persone/);
  if(m){ settings.people=Number(m[1]||m[2]); saveAll(); render(); return `Ok, ho aggiornato il profilo: ${settings.people} persone in casa. Ora ricalcolo acqua, alimenti e scorte.`; }
  m=q.match(/(?:ho|abbiamo|siamo).*?(\d+)\s+(?:animali|cani|gatti)|(?:metti|imposta|aggiorna).*?(\d+)\s+(?:animali|cani|gatti)/);
  if(m){ settings.animals=Number(m[1]||m[2]); saveAll(); render(); return `Ok, ho aggiornato il profilo: ${settings.animals} animali. Ora ricalcolo crocchette, sacchetti e prodotti animali.`; }
  m=q.match(/(?:segna|imposta|metti|porta)\s+(.+?)\s+(?:a|ad)\s+(\d+(?:[\.,]\d+)?)\s*([a-z]*)/);
  if(m){
    const item=findItemBySpeech(m[1]);
    if(!item) return `Non ho trovato “${m[1]}”. Posso aggiungerlo come nuovo articolo se mi dici la categoria.`;
    const old=item.qty; item.qty=Number(m[2].replace(',','.')); if(m[3]) item.unit=m[3];
    if(item.qty<old) rememberEvent('consume',item,old-item.qty,'AI set quantity'); else if(item.qty>old) rememberEvent('restock',item,item.qty-old,'AI set quantity');
    item.updatedAt=Date.now(); saveAll(); render(); return `Fatto: ${nameOf(item)} ora è a ${item.qty} ${item.unit}. Ho aggiornato anche i consumi.`;
  }
  if(q.includes('aggiungi') || q.includes('metti in lista') || q.includes('comprare')){
    const guess=raw.replace(/hey\s+spesa\s+pronta[:,]?/i,'').replace(/aggiungi|metti in lista|da comprare|comprare|alla lista/gi,'').trim();
    const item=findItemBySpeech(guess||raw);
    if(item){ const old=item.qty; item.qty=0; item.usage=(item.usage||0)+1; rememberEvent('consume',item,old,'AI add to list'); item.updatedAt=Date.now(); saveAll(); render(); return `Ok, ho messo ${nameOf(item)} nella lista della spesa.`; }
    const names={it:guess||'Nuovo articolo', en:guess||'New item', es:guess||'Nuevo artículo', de:guess||'Neuer Artikel'};
    const newItem=createItem(cryptoId(),'assets/illustrations/generic-item.png','food',names,0,6,2,['pz','pc','kg','lt'],{custom:true,usage:1});
    state.unshift(newItem); rememberEvent('consume',newItem,1,'AI created item'); saveAll(); render(); return `Non era nel catalogo: ho creato “${names.it}” e l'ho messo nella lista.`;
  }
  if(q.includes('perche') || q.includes('spiega')){
    const item=findItemBySpeech(raw) || [...state].sort((a,b)=>suggestionScore(b)-suggestionScore(a))[0];
    return item ? aiExplainItem(item) : 'Uso persone, animali, storico consumi, soglia minima e giorni stimati per decidere cosa suggerire.';
  }
  if(q.includes('consumi') || q.includes('analisi')){
    const urgent=[...state].sort((a,b)=>suggestionScore(b)-suggestionScore(a)).slice(0,4);
    return householdInsightText()+'\n'+urgent.map(aiExplainItem).join('\n');
  }
  if(q.includes('ricorda') || q.includes('ricordati')){
    aiMemory.facts=aiMemory.facts||[]; aiMemory.facts.push({text:raw,at:Date.now()}); aiMemory.facts=aiMemory.facts.slice(-80); saveAiMemory(); return 'Memorizzato. Userò questa informazione per adattare meglio i suggerimenti.';
  }
  const backend = await askBackendAi(raw).catch(()=>null);
  if(backend) return backend;
  return `Ho capito. Lo tengo a mente e continuo ad adattarmi a te. Posso leggere la lista, aggiungere articoli, modificare quantità, aggiornare persone/animali, ricordare preferenze e analizzare foto spesa. Prova: “hey spesa pronta, fotografa la spesa”.`;
}
async function askBackendAi(message){
  if(!settings.apiEndpoint) return null;
  const res=await fetch(`${settings.apiEndpoint.replace(/\/$/,'')}/ai/chat`,{
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':`Bearer ${settings.token||''}`},
    body:JSON.stringify({message,state,settings,memory:aiMemory,householdId:settings.householdId})
  });
  if(!res.ok) return null;
  const data=await res.json();
  if(data.memory){ const localBrain=aiMemory.visionBrain; aiMemory=Object.assign(aiMemory,data.memory); aiMemory.learnedProducts=Array.isArray(aiMemory.learnedProducts)?aiMemory.learnedProducts:[]; aiMemory.productDeepMemory=Array.isArray(aiMemory.productDeepMemory)?aiMemory.productDeepMemory:[]; aiMemory.productMemoryIndex=aiMemory.productMemoryIndex||{}; aiMemory.visionBrain=Object.assign(defaultAiMemory().visionBrain, aiMemory.visionBrain||{}, localBrain||{}); saveAiMemory(); }
  return data.reply || null;
}


