    window.SPESA_PRONTA_BUILD=Object.assign({}, window.SPESA_PRONTA_BUILD||{}, {version:'V28.52', costFirewall:'one_openai_call_max_tiny_images', expiryMicroIdentity:'dot_matrix_expiry_low_token_name_probe'});
