      let formats=[]; try{ formats=await Detector.getSupportedFormats(); }catch(_){ formats=['ean_13','ean_8','upc_a','upc_e','code_128']; }
      const wanted=['ean_13','ean_8','upc_a','upc_e','code_128','itf'];
